@Component
class RedirectUriValidator {

    private static final Logger logger = Logger.getLogger(RedirectUriValidator.class.getName());

    /**
     * Validates the redirect_uri using EXACT MATCH against registered URIs.
     * 
     * This is the ONLY secure way to validate redirect URIs per RFC 6819 Section 4.4.1.7.
     * 
     * We do NOT:
     * - Allow prefix/startsWith matching (vulnerable to path traversal)
     * - Allow dynamic subdomains (vulnerable to subdomain takeover)
     * - Allow pattern matching or wildcards
     * - Allow any form of partial matching
     * 
     * Each redirect URI must be pre-registered exactly as it will be used.
     */
    public boolean isValidRedirectUri(String redirectUri, RegisteredClient client) {
        if (redirectUri == null || redirectUri.isBlank()) {
            logger.warning("Redirect URI is null or blank for client: " + client.getClientId());
            return false;
        }

        // Parse and normalize the URI to prevent encoding tricks
        URI parsedUri;
        try {
            parsedUri = new URI(redirectUri);
        } catch (URISyntaxException e) {
            logger.warning("Malformed redirect URI for client: " + client.getClientId());
            return false;
        }

        // Must be an absolute URI with https scheme
        if (!parsedUri.isAbsolute()) {
            logger.warning("Redirect URI is not absolute for client: " + client.getClientId());
            return false;
        }

        String scheme = parsedUri.getScheme();
        if (scheme == null || !scheme.equals("https")) {
            logger.warning("Redirect URI does not use HTTPS for client: " + client.getClientId());
            return false;
        }

        // Reject URIs with fragments (per OAuth 2.0 spec)
        if (parsedUri.getFragment() != null) {
            logger.warning("Redirect URI contains fragment for client: " + client.getClientId());
            return false;
        }

        // Reject URIs with userinfo component (e.g., https://attacker@legitimate.com)
        if (parsedUri.getUserInfo() != null) {
            logger.warning("Redirect URI contains userinfo for client: " + client.getClientId());
            return false;
        }

        // Reject URIs with suspicious path components
        String path = parsedUri.getPath();
        if (path != null && (path.contains("..") || path.contains("//") || path.contains("\\") || path.contains("%"))) {
            logger.warning("Redirect URI contains suspicious path components for client: " + client.getClientId());
            return false;
        }

        // Normalize the URI for comparison: reconstruct from parsed components
        String normalizedUri;
        try {
            URI normalized = new URI(
                parsedUri.getScheme(),
                null, // no userinfo
                parsedUri.getHost(),
                parsedUri.getPort(),
                parsedUri.getPath(),
                parsedUri.getQuery(),
                null  // no fragment
            );
            normalizedUri = normalized.toString();
        } catch (URISyntaxException e) {
            logger.warning("Failed to normalize redirect URI for client: " + client.getClientId());
            return false;
        }

        // EXACT MATCH against registered URIs - the only secure approach
        for (String registeredUri : client.getRegisteredRedirectUris()) {
            try {
                URI registeredParsed = new URI(registeredUri);
                URI registeredNormalized = new URI(
                    registeredParsed.getScheme(),
                    null,
                    registeredParsed.getHost(),
                    registeredParsed.getPort(),
                    registeredParsed.getPath(),
                    registeredParsed.getQuery(),
                    null
                );
                if (registeredNormalized.toString().equals(normalizedUri)) {
                    return true;
                }
            } catch (URISyntaxException e) {
                // Skip malformed registered URIs (should not happen if properly configured)
                logger.severe("Malformed registered redirect URI: " + registeredUri);
            }
        }

        // Do NOT log the actual redirect URI to prevent log injection
        logger.warning("Redirect URI did not match any registered URI for client: " + client.getClientId());
        return false;
    }
}

class AuthorizationCode {
    private final String code;
    private final String clientId;
    private final String redirectUri;
    private final String userId;
    private final Set<String> scopes;
    private final Instant expiresAt;
    private final String codeChallenge;
    private final String codeChallengeMethod;
    private volatile boolean used;

    public AuthorizationCode(String code, String clientId, String redirectUri,
                             String userId, Set<String> scopes, Instant expiresAt,
                             String codeChallenge, String codeChallengeMethod) {
        this.code = code;
        this.clientId = clientId;
        this.redirectUri = redirectUri;
        this.userId = userId;
        this.scopes = Collections.unmodifiableSet(new HashSet<>(scopes));
        this.expiresAt = expiresAt;
        this.codeChallenge = codeChallenge;
        this.codeChallengeMethod = codeChallengeMethod;
        this.used = false;
    }

    public String getCode() { return code; }
    public String getClientId() { return clientId; }
    public String getRedirectUri() { return redirectUri; }
    public String getUserId() { return userId; }
    public Set<String> getScopes() { return scopes; }
    public Instant getExpiresAt() { return expiresAt; }
    public String getCodeChallenge() { return codeChallenge; }
    public String getCodeChallengeMethod() { return codeChallengeMethod; }
    public boolean isUsed() { return used; }

    public synchronized boolean markUsed() {
        if (used) return false;
        used = true;
        return true;
    }

    public boolean isExpired() {
        return Instant.now().isAfter(expiresAt);
    }
}

@Component
class AuthorizationCodeStore {

    private static final Logger logger = Logger.getLogger(AuthorizationCodeStore.class.getName());
    private static final long CODE_EXPIRATION_MINUTES = 10;
    private static final int CODE_BYTE_LENGTH = 32;

    private final ConcurrentHashMap<String, AuthorizationCode> codes = new ConcurrentHashMap<>();
    private final SecureRandom secureRandom = new SecureRandom();
    private final ScheduledExecutorService cleanupExecutor = Executors.newSingleThreadScheduledExecutor(r -> {
        Thread t = new Thread(r, "auth-code-cleanup");
        t.setDaemon(true);
        return t;
    });

    @PostConstruct
    public void init() {
        // Clean up expired codes every minute
        cleanupExecutor.scheduleAtFixedRate(this::cleanupExpiredCodes, 1, 1, TimeUnit.MINUTES);
    }

    public AuthorizationCode createCode(String clientId, String redirectUri, String userId,
                                         Set<String> scopes, String codeChallenge,
                                         String codeChallengeMethod) {
        String code = generateSecureCode();
        Instant expiresAt = Instant.now().plusSeconds(CODE_EXPIRATION_MINUTES * 60);

        AuthorizationCode authCode = new AuthorizationCode(
            code, clientId, redirectUri, userId, scopes, expiresAt,
            codeChallenge, codeChallengeMethod
        );

        codes.put(code, authCode);
        logger.info("Authorization code created for client: " + clientId + ", user: " + userId);
        return authCode;
    }

    public Optional<AuthorizationCode> consumeCode(String code) {
        if (code == null || code.isBlank()) {
            return Optional.empty();
        }

        AuthorizationCode authCode = codes.remove(code);
        if (authCode == null) {
            return Optional.empty();
        }

        if (authCode.isExpired()) {
            logger.warning("Attempted to use expired authorization code for client: " + authCode.getClientId());
            return Optional.empty();
        }

        // Ensure single-use: if already used, revoke and reject
        if (!authCode.markUsed()) {
            logger.severe("Authorization code replay detected for client: " + authCode.getClientId()
                + ". Potential attack - code was already used.");
            return Optional.empty();
        }

        return Optional.of(authCode);
    }

    private String generateSecureCode() {
        byte[] bytes = new byte[CODE_BYTE_LENGTH];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private void cleanupExpiredCodes() {
        int removed = 0;
        Iterator<Map.Entry<String, AuthorizationCode>> iterator = codes.entrySet().iterator();
        while (iterator.hasNext()) {
            Map.Entry<String, AuthorizationCode> entry = iterator.next();
            if (entry.getValue().isExpired()) {
                iterator.remove();
                removed++;
            }
        }
        if (removed > 0) {
            logger.info("Cleaned up " + removed + " expired authorization codes");
        }
    }
}

@Controller
class OAuthAuthorizationController {

    private static final Logger logger = Logger.getLogger(OAuthAuthorizationController.class.getName());
    private static final Set<String> VALID_RESPONSE_TYPES = Set.of("code");
    private static final int MAX_STATE_LENGTH = 512;
    private static final int MAX_SCOPE_LENGTH = 256;

    private final RegisteredClientRepository clientRepository;
    private final RedirectUriValidator redirectUriValidator;
    private final AuthorizationCodeStore authorizationCodeStore;

    public OAuthAuthorizationController(RegisteredClientRepository clientRepository,
                                         RedirectUriValidator redirectUriValidator,
                                         AuthorizationCodeStore authorizationCodeStore) {
        this.clientRepository = clientRepository;
        this.redirectUriValidator = redirectUriValidator;
        this.authorizationCodeStore = authorizationCodeStore;
    }

    @GetMapping("/oauth/authorize")
    public void authorize(
            @RequestParam(value = "response_type", required = false) String responseType,
            @RequestParam(value = "client_id", required = false) String clientId,
            @RequestParam(value = "redirect_uri", required = false) String redirectUri,
            @RequestParam(value = "scope", required = false) String scope,
            @RequestParam(value = "state", required = false) String state,
            @RequestParam(value = "code_challenge", required = false) String codeChallenge,
            @RequestParam(value = "code_challenge_method", required = false) String codeChallengeMethod,
            HttpServletRequest request,
            HttpServletResponse response) throws IOException {

        // Step 1: Validate response_type
        if (responseType == null || !VALID_RESPONSE_TYPES.contains(responseType)) {
            sendErrorPage(response, HttpServletResponse.SC_BAD_REQUEST,
                "Invalid or missing response_type parameter.");
            return;
        }

        // Step 2: Validate client_id and look up client
        if (clientId == null || clientId.isBlank()) {
            sendErrorPage(response, HttpServletResponse.SC_BAD_REQUEST,
                "Missing client_id parameter.");
            return;
        }

        Optional<RegisteredClient> clientOpt = clientRepository.findByClientId(clientId);
        if (clientOpt.isEmpty()) {
            logger.warning("Authorization request with unknown client_id: " + sanitizeForLog(clientId));
            sendErrorPage(response, HttpServletResponse.SC_BAD_REQUEST,
                "Unknown client.");
            return;
        }

        RegisteredClient client = clientOpt.get();

        // Step 3: Validate grant type
        if (!client.getAllowedGrantTypes().contains("authorization_code")) {
            sendErrorPage(response, HttpServletResponse.SC_BAD_REQUEST,
                "Client is not authorized for this grant type.");
            return;
        }

        // Step 4: Validate redirect_uri - CRITICAL SECURITY CHECK
        // Per RFC 6749 Section 3.1.2.3: exact match required
        if (redirectUri == null || redirectUri.isBlank()) {
            // If only one redirect URI is registered, we can use it as default
            if (client.getRegisteredRedirectUris().size() == 1) {
                redirectUri = client.getRegisteredRedirectUris().iterator().next();
            } else {
                sendErrorPage(response, HttpServletResponse.SC_BAD_REQUEST,
                    "Missing redirect_uri parameter.");
                return;
            }
        }

        if (!redirectUriValidator.isValidRedirectUri(redirectUri, client)) {
            // IMPORTANT: Do NOT redirect to the invalid URI
            // Display error directly to the user instead
            logger.warning("Invalid redirect_uri in authorization request for client: " + clientId);
            sendErrorPage(response, HttpServletResponse.SC_BAD_REQUEST,
                "Invalid redirect URI.");
            return;
        }

        // Step 5: Validate state parameter (recommended per RFC 6749)
        if (state != null && state.length() > MAX_STATE_LENGTH) {
            sendRedirectError(response, redirectUri, "invalid_request",
                "State parameter too long.", state);
            return;
        }

        // Step 6: Validate and filter scopes
        Set<String> requestedScopes = parseAndValidateScopes(scope, client);
        if (requestedScopes == null) {
            sendRedirectError(response, redirectUri, "invalid_scope",
                "Invalid scope requested.", state);
            return;
        }

        // Step 7: Validate PKCE parameters (recommended for all clients)
        if (codeChallenge != null) {
            if (codeChallengeMethod == null || !codeChallengeMethod.equals("S256")) {
                sendRedirectError(response, redirectUri, "invalid_request",
                    "Only S256 code_challenge_method is supported.", state);
                return;
            }
            if (!isValidCodeChallenge(codeChallenge)) {
                sendRedirectError(response, redirectUri, "invalid_request",
                    "Invalid code_challenge format.", state);
                return;
            }
        }

        // Step 8: Get authenticated user
        String userId = request.getUserPrincipal().getName();

        // Step 9: Generate authorization code
        AuthorizationCode authCode = authorizationCodeStore.createCode(
            clientId, redirectUri, userId, requestedScopes,
            codeChallenge, codeChallengeMethod
        );

        // Step 10: Build redirect response
        StringBuilder redirectBuilder = new StringBuilder(redirectUri);
        redirectBuilder.append(redirectUri.contains("?") ? "&" : "?");
        redirectBuilder.append("code=").append(urlEncode(authCode.getCode()));
        if (state != null && !state.isBlank()) {
            redirectBuilder.append("&state=").append(urlEncode(state));
        }

        String finalRedirect = redirectBuilder.toString();

        // Final validation: ensure the constructed redirect still matches the registered URI's origin
        if (!redirectUriValidator.isValidRedirectUri(extractBaseUri(finalRedirect), client)) {
            logger.severe("Redirect URI manipulation detected after code generation for client: " + clientId);
            sendErrorPage(response, HttpServletResponse.SC_BAD_REQUEST, "Invalid request.");
            return;
        }

        logger.info("Authorization code issued for client: " + clientId + ", user: " + userId);
        response.sendRedirect(finalRedirect);
    }

    @GetMapping("/login")
    public String loginPage() {
        return "login";
    }

    private Set<String> parseAndValidateScopes(String scopeParam, RegisteredClient client) {
        if (scopeParam == null || scopeParam.isBlank()) {
            // Return default scopes or all allowed scopes
            return new HashSet<>(client.getAllowedScopes());
        }

        if (scopeParam.length() > MAX_SCOPE_LENGTH) {
            return null;
        }

        // Validate scope string contains only allowed characters
        if (!scopeParam.matches("^[a-zA-Z0-9_ ]+$")) {
            return null;
        }

        String[] requestedScopes = scopeParam.split("\\s+");
        Set<String> validScopes = new HashSet<>();

        for (String s : requestedScopes) {
            String trimmed = s.trim();
            if (!trimmed.isEmpty()) {
                if (!client.getAllowedScopes().contains(trimmed)) {
                    return null; // Requested scope not allowed for this client
                }
                validScopes.add(trimmed);
            }
        }

        return validScopes.isEmpty() ? null : validScopes;
    }

    private boolean isValidCodeChallenge(String codeChallenge) {
        // RFC 7636: code_challenge is base64url-encoded SHA256 hash (43 characters)
        return codeChallenge != null
            && codeChallenge.length() == 43
            && codeChallenge.matches("^[A-Za-z0-9_-]+$");
    }

    private void sendRedirectError(HttpServletResponse response, String redirectUri,
                                    String error, String description, String state) throws IOException {
        StringBuilder errorRedirect = new StringBuilder(redirectUri);
        errorRedirect.append(redirectUri.contains("?") ? "&" : "?");
        errorRedirect.append("error=").append(urlEncode(error));
        if (description != null) {
            errorRedirect.append("&error_description=").append(urlEncode(description));
        }
        if (state != null && !state.isBlank()) {
            errorRedirect.append("&state=").append(urlEncode(state));
        }
        response.sendRedirect(errorRedirect.toString());
    }

    private void sendErrorPage(HttpServletResponse response, int statusCode, String message) throws IOException {
        response.setStatus(statusCode);
        response.setContentType("text/html;charset=UTF-8");
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("Cache-Control", "no-store");
        response.setHeader("Pragma", "no-cache");
        // Escape HTML to prevent XSS
        String escapedMessage = escapeHtml(message);
        response.getWriter().write(
            "<!DOCTYPE html><html><head><title>Error</title></head><body>"
            + "<h1>Authorization Error</h1><p>" + escapedMessage + "</p></body></html>"
        );
    }

    private String extractBaseUri(String fullUri) {
        int queryIndex = fullUri.indexOf('?');
        return queryIndex > 0 ? fullUri.substring(0, queryIndex) : fullUri;
    }

    private String urlEncode(String value) {
        try {
            return java.net.URLEncoder.encode(value, "UTF-8");
        } catch (java.io.UnsupportedEncodingException e) {
            throw new RuntimeException("UTF-8 encoding not supported", e);
        }
    }

    private String escapeHtml(String input) {
        if (input == null) return "";
        return input
            .replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace("\"", "&quot;")
            .replace("'", "&#x27;");
    }

    private String sanitizeForLog(String input) {
        if (input == null) return "null";
        // Remove newlines and control characters to prevent log injection
        return input.replaceAll("[\\r\\n\\t]", "_").substring(0, Math.min(input.length(), 100));
    }
}

@RestController
@RequestMapping("/oauth")
class OAuthTokenController {

    private static final Logger logger = Logger.getLogger(OAuthTokenController.class.getName());

    private final AuthorizationCodeStore authorizationCodeStore;
    private final RegisteredClientRepository clientRepository;
    private final RedirectUriValidator redirectUriValidator;
    private final PasswordEncoder passwordEncoder;

    public OAuthTokenController(AuthorizationCodeStore authorizationCodeStore,
                                 RegisteredClientRepository clientRepository,
                                 RedirectUriValidator redirectUriValidator,
                                 PasswordEncoder passwordEncoder) {
        this.authorizationCodeStore = authorizationCodeStore;
        this.clientRepository = clientRepository;
        this.redirectUriValidator = redirectUriValidator;
        this.passwordEncoder = passwordEncoder;
    }

    @PostMapping("/token")
    public Object token(
            @RequestParam(value = "grant_type", required = false) String grantType,
            @RequestParam(value = "code", required = false) String code,
            @RequestParam(value = "redirect_uri", required = false) String redirectUri,
            @RequestParam(value = "client_id", required = false) String clientId,
            @RequestParam(value = "client_secret", required = false) String clientSecret,
            @RequestParam(value = "code_verifier", required = false) String codeVerifier,
            HttpServletResponse response) {

        response.setHeader("Cache-Control", "no-store");
        response.setHeader("Pragma", "no-cache");

        // Validate grant_type
        if (!"authorization_code".equals(grantType)) {
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            return Map.of("error", "unsupported_grant_type",
                "error_description", "Only authorization_code grant type is supported.");
        }

        // Validate client credentials
        if (clientId == null || clientSecret == null) {
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            return Map.of("error", "invalid_client",
                "error_description", "Client authentication failed.");
        }

        Optional<RegisteredClient> clientOpt = clientRepository.findByClientId(clientId);
        if (clientOpt.isEmpty()) {
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            return Map.of("error", "invalid_client",
                "error_description", "Client authentication failed.");
        }

        RegisteredClient client = clientOpt.get();

        // Constant-time comparison of client secret
        if (!passwordEncoder.matches(clientSecret, client.getClientSecretHash())) {
            logger.warning("Failed client authentication for client: " + clientId);
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            return Map.of("error", "invalid_client",
                "error_description", "Client authentication failed.");
        }

        // Consume authorization code (single-use)
        if (code == null || code.isBlank()) {
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            return Map.of("error", "invalid_grant",
                "error_description", "Missing authorization code.");
        }

        Optional<AuthorizationCode> authCodeOpt = authorizationCodeStore.consumeCode(code);
        if (authCodeOpt.isEmpty()) {
            logger.warning("Invalid or expired authorization code used by client: " + clientId);
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            return Map.of("error", "invalid_grant",
                "error_description", "Invalid, expired, or already used authorization code.");
        }

        AuthorizationCode authCode = authCodeOpt.get();

        // Verify the code was issued to this client
        if (!authCode.getClientId().equals(clientId)) {
            logger.severe("Authorization code client mismatch. Code client: "
                + authCode.getClientId() + ", requesting client: " + clientId);
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            return Map.of("error", "invalid_grant",
                "error_description", "Authorization code was not issued to this client.");
        }

        // Verify redirect_uri matches the one used in the authorization request
        if (redirectUri != null && !redirectUri.equals(authCode.getRedirectUri())) {
            logger.warning("Redirect URI mismatch in token request for client: " + clientId);
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            return Map.of("error", "invalid_grant",
                "error_description", "Redirect URI mismatch.");
        }

        // Verify PKCE code_verifier if code_challenge was provided
        if (authCode.getCodeChallenge() != null) {
            if (codeVerifier == null || codeVerifier.isBlank()) {
                response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
                return Map.of("error", "invalid_grant",
                    "error_description", "Code verifier required.");
            }
            if (!verifyCodeChallenge(codeVerifier, authCode.getCodeChallenge())) {
                logger.warning("PKCE verification failed for client: " + clientId);
                response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
                return Map.of("error", "invalid_grant",
                    "error_description", "Code verifier validation failed.");
            }
        }

        // Generate tokens (in production, use JWT with proper signing)
        String accessToken = generateSecureToken();
        String refreshToken = generateSecureToken();

        logger.info("Access token issued for client: " + clientId + ", user: " + authCode.getUserId());

        return Map.of(
            "access_token", accessToken,
            "token_type", "Bearer",
            "expires_in", 3600,
            "refresh_token", refreshToken,
            "scope", String.join(" ", authCode.getScopes())
        );
    }

    private boolean verifyCodeChallenge(String codeVerifier, String codeChallenge) {
        try {
            java.security.MessageDigest digest = java.security.MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(codeVerifier.getBytes(java.nio.charset.StandardCharsets.US_ASCII));
            String computed = Base64.getUrlEncoder().withoutPadding().encodeToString(hash);
            return java.security.MessageDigest.isEqual(
                computed.getBytes(java.nio.charset.StandardCharsets.UTF_8),
                codeChallenge.getBytes(java.nio.charset.StandardCharsets.UTF_8)
            );
        } catch (java.security.NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-256 not available", e);
        }
    }

    private String generateSecureToken() {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }
}